"""Calibration metrics: Brier, log-loss, ECE, reliability, resolution, coverage."""

from __future__ import annotations

import math
from typing import Any

from noosphere.models import CalibrationMetrics, OutcomeKind

from noosphere.evaluation.outcomes import ResolutionResult

_EPS = 1e-15


def brier_score(results: list[ResolutionResult]) -> float:
    if not results:
        return 0.0
    return sum(r.score for r in results) / len(results)


def log_loss(results: list[ResolutionResult]) -> float:
    if not results:
        return 0.0
    total = 0.0
    for r in results:
        if r.kind == OutcomeKind.BINARY:
            p = float(r.predicted)
            y = 1.0 if r.actual else 0.0
            p = max(_EPS, min(1.0 - _EPS, p))
            total += -(y * math.log(p) + (1.0 - y) * math.log(1.0 - p))
        elif r.kind == OutcomeKind.INTERVAL:
            total += r.score
        elif r.kind == OutcomeKind.PREFERENCE:
            if isinstance(r.predicted, dict):
                probs = r.predicted.get("probabilities", {})
                if probs and r.actual in probs:
                    p = max(_EPS, min(1.0 - _EPS, float(probs[r.actual])))
                    total += -math.log(p)
                else:
                    total += r.score
            else:
                total += r.score
    return total / len(results)


def reliability_bins(
    results: list[ResolutionResult], n_bins: int = 10
) -> list[dict[str, Any]]:
    bins: list[list[ResolutionResult]] = [[] for _ in range(n_bins)]
    for r in results:
        if r.kind == OutcomeKind.BINARY:
            p = float(r.predicted)
            idx = min(int(p * n_bins), n_bins - 1)
            bins[idx].append(r)

    out: list[dict[str, Any]] = []
    for i, bucket in enumerate(bins):
        lower = i / n_bins
        upper = (i + 1) / n_bins
        if not bucket:
            out.append({
                "bin_lower": round(lower, 4),
                "bin_upper": round(upper, 4),
                "count": 0,
                "mean_predicted": 0.0,
                "mean_observed": 0.0,
            })
            continue
        mean_pred = sum(float(r.predicted) for r in bucket) / len(bucket)
        mean_obs = sum(1.0 if r.actual else 0.0 for r in bucket) / len(bucket)
        out.append({
            "bin_lower": round(lower, 4),
            "bin_upper": round(upper, 4),
            "count": len(bucket),
            "mean_predicted": round(mean_pred, 6),
            "mean_observed": round(mean_obs, 6),
        })
    return out


def ece(results: list[ResolutionResult], n_bins: int = 10) -> float:
    bins_data = reliability_bins(results, n_bins=n_bins)
    total_count = sum(b["count"] for b in bins_data)
    if total_count == 0:
        return 0.0
    weighted_sum = 0.0
    for b in bins_data:
        if b["count"] == 0:
            continue
        weighted_sum += b["count"] * abs(b["mean_predicted"] - b["mean_observed"])
    return weighted_sum / total_count


def resolution_score(results: list[ResolutionResult]) -> float:
    if not results:
        return 0.0
    binary = [r for r in results if r.kind == OutcomeKind.BINARY]
    if not binary:
        return 0.0
    base_rate = sum(1.0 if r.actual else 0.0 for r in binary) / len(binary)
    return sum((float(r.predicted) - base_rate) ** 2 for r in binary) / len(binary)


def coverage(total_outcomes: int, resolved_count: int) -> float:
    if total_outcomes == 0:
        return 0.0
    return resolved_count / total_outcomes


def compute_metrics_for_kind(
    results: list[ResolutionResult],
    kind: OutcomeKind,
    total_outcomes: int,
) -> CalibrationMetrics:
    filtered = [r for r in results if r.kind == kind and r.resolved]
    return CalibrationMetrics(
        brier=round(brier_score(filtered), 6),
        log_loss=round(log_loss(filtered), 6),
        ece=round(ece(filtered), 6),
        reliability_bins=reliability_bins(filtered),
        resolution=round(resolution_score(filtered), 6),
        coverage=round(coverage(total_outcomes, len(filtered)), 6),
    )


def compute_metrics(
    results: list[ResolutionResult],
    total_outcomes_by_kind: dict[OutcomeKind, int],
) -> dict[OutcomeKind, CalibrationMetrics]:
    out: dict[OutcomeKind, CalibrationMetrics] = {}
    for kind, total in total_outcomes_by_kind.items():
        out[kind] = compute_metrics_for_kind(results, kind, total)
    return out

from __future__ import annotations

import contextvars
import hashlib
import json
import logging
import os
import subprocess
from datetime import datetime, timezone
from functools import wraps
from typing import Any, Callable
from uuid import uuid4

from pydantic import BaseModel

from noosphere.models import (
    CascadeEdgeRelation,
    Method,
    MethodImplRef,
    MethodInvocation,
    MethodType,
)
from noosphere.methods._hooks import _FAILURE_HOOKS, _POST_HOOKS, _PRE_HOOKS
from noosphere.methods._registry import REGISTRY

logger = logging.getLogger(__name__)

CORRELATION_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "CORRELATION_ID", default=""
)
TENANT_ID: contextvars.ContextVar[str] = contextvars.ContextVar(
    "TENANT_ID", default="default"
)

_store_factory: Callable[..., Any] | None = None


def set_store_factory(factory: Callable[..., Any]) -> None:
    global _store_factory
    _store_factory = factory


def _get_store() -> Any:
    if _store_factory is not None:
        try:
            return _store_factory()
        except Exception:
            return None
    return None


def _canonical_json(obj: Any) -> str:
    if isinstance(obj, BaseModel):
        obj = obj.model_dump(mode="json")
    return json.dumps(obj, sort_keys=True, separators=(",", ":"), default=str)


def _current_git_sha() -> str:
    sha = os.environ.get("THESEUS_GIT_SHA")
    if sha:
        return sha
    try:
        result = subprocess.run(
            ["git", "rev-parse", "HEAD"],
            capture_output=True,
            text=True,
            timeout=5,
        )
        if result.returncode == 0:
            return result.stdout.strip()
    except Exception:
        pass
    return "unknown"


def _current_correlation_id() -> str:
    return CORRELATION_ID.get()


def _current_tenant_id() -> str:
    return TENANT_ID.get()


def _validate_against_schema(schema: Any, data: Any) -> Any:
    if isinstance(schema, type) and issubclass(schema, BaseModel):
        if isinstance(data, schema):
            return data
        return schema.model_validate(data)
    if isinstance(schema, dict) and schema:
        try:
            import jsonschema as _js

            _js.validate(data, schema)
        except ImportError:
            pass
    return data


def _utcnow() -> datetime:
    return datetime.now(timezone.utc)


def _run_failure_path(
    spec: Method,
    inv: MethodInvocation,
    validated_input: Any,
    exc: BaseException,
) -> None:
    inv = inv.model_copy(
        update={
            "ended_at": _utcnow(),
            "succeeded": False,
            "error_kind": type(exc).__name__,
        }
    )
    for hook_name, hook in _FAILURE_HOOKS:
        try:
            hook(spec, inv, validated_input, exc)
        except Exception:
            logger.exception("Failure hook %s raised", hook_name)
    store = _get_store()
    if store is not None:
        try:
            store.insert_method_invocation(inv)
        except Exception:
            logger.exception("Failed to persist invocation")


def register_method(
    *,
    name: str,
    version: str,
    method_type: MethodType,
    input_schema: Any,
    output_schema: Any,
    description: str,
    rationale: str,
    preconditions: list[str] | tuple[str, ...] = (),
    postconditions: list[str] | tuple[str, ...] = (),
    dependencies: list[tuple[str, str]] | tuple[tuple[str, str], ...] = (),
    owner: str,
    status: str = "active",
    nondeterministic: bool = False,
    emits_edges: list[CascadeEdgeRelation] | tuple[CascadeEdgeRelation, ...] = (),
) -> Callable:
    def decorator(fn: Callable) -> Callable:
        if isinstance(input_schema, type) and issubclass(input_schema, BaseModel):
            in_schema_dict = input_schema.model_json_schema()
        elif isinstance(input_schema, dict):
            in_schema_dict = input_schema
        else:
            in_schema_dict = {}

        if isinstance(output_schema, type) and issubclass(output_schema, BaseModel):
            out_schema_dict = output_schema.model_json_schema()
        elif isinstance(output_schema, dict):
            out_schema_dict = output_schema
        else:
            out_schema_dict = {}

        impl = MethodImplRef(
            module=fn.__module__,
            fn_name=fn.__qualname__,
            git_sha=_current_git_sha(),
            image_digest=None,
        )

        spec_for_hash = {
            "name": name,
            "version": version,
            "method_type": method_type.value,
            "input_schema": in_schema_dict,
            "output_schema": out_schema_dict,
            "description": description,
            "rationale": rationale,
            "preconditions": list(preconditions),
            "postconditions": list(postconditions),
            "dependencies": [list(d) for d in dependencies],
            "implementation": impl.model_dump(mode="json"),
            "owner": owner,
            "status": status,
            "nondeterministic": nondeterministic,
        }

        method_id = hashlib.sha256(
            _canonical_json(spec_for_hash).encode()
        ).hexdigest()[:32]

        spec = Method(
            method_id=method_id,
            name=name,
            version=version,
            method_type=method_type,
            input_schema=in_schema_dict,
            output_schema=out_schema_dict,
            description=description,
            rationale=rationale,
            preconditions=list(preconditions),
            postconditions=list(postconditions),
            dependencies=list(dependencies),
            implementation=impl,
            owner=owner,
            status=status,
            nondeterministic=nondeterministic,
            created_at=_utcnow(),
        )

        @wraps(fn)
        def wrapped(input_data: Any) -> Any:
            validated_input = _validate_against_schema(input_schema, input_data)
            input_hash = hashlib.sha256(
                _canonical_json(validated_input).encode()
            ).hexdigest()

            inv = MethodInvocation(
                id=str(uuid4()),
                method_id=spec.method_id,
                input_hash=input_hash,
                output_hash="",
                started_at=_utcnow(),
                ended_at=None,
                succeeded=False,
                error_kind=None,
                correlation_id=_current_correlation_id(),
                tenant_id=_current_tenant_id(),
            )

            try:
                for _hook_name, hook in _PRE_HOOKS:
                    hook(spec, inv, validated_input)
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

            try:
                result = fn(validated_input)
                _validate_against_schema(output_schema, result)
                output_hash = hashlib.sha256(
                    _canonical_json(result).encode()
                ).hexdigest()
                inv = inv.model_copy(
                    update={
                        "ended_at": _utcnow(),
                        "succeeded": True,
                        "output_hash": output_hash,
                    }
                )

                for hook_name, hook in _POST_HOOKS:
                    try:
                        hook(spec, inv, validated_input, result)
                    except Exception:
                        logger.exception("Post-hook %s raised", hook_name)

                store = _get_store()
                if store is not None:
                    try:
                        store.insert_method_invocation(inv)
                    except Exception:
                        logger.exception("Failed to persist invocation")

                return result
            except Exception as e:
                _run_failure_path(spec, inv, validated_input, e)
                raise

        wrapped.__method_spec__ = spec  # type: ignore[attr-defined]

        REGISTRY.register(spec, wrapped)

        if emits_edges:
            REGISTRY.set_emits_edges(method_id, list(emits_edges))

        store = _get_store()
        if store is not None:
            try:
                store.insert_method(spec)
            except Exception:
                logger.exception("Failed to persist method spec")

        return wrapped

    return decorator

"""Outcome resolution for calibration evaluation."""

from __future__ import annotations

from dataclasses import dataclass
from typing import Any, Optional

from noosphere.models import Outcome, OutcomeKind


class ResolutionError(Exception):
    """Raised when resolution logic cannot proceed."""


@dataclass(frozen=True)
class ResolutionResult:
    """Result of resolving an outcome against a prediction."""
    outcome_id: str
    kind: OutcomeKind
    predicted: Any
    actual: Any
    score: float
    resolved: bool
    resolution_source: str
    detail: str = ""


def _resolve_binary(outcome: Outcome, prediction: Any) -> ResolutionResult:
    actual = bool(outcome.value)
    if isinstance(prediction, (int, float)):
        prob = float(prediction)
    elif isinstance(prediction, bool):
        prob = 1.0 if prediction else 0.0
    elif isinstance(prediction, dict) and "probability" in prediction:
        prob = float(prediction["probability"])
    else:
        raise ResolutionError(
            f"Cannot interpret prediction for binary outcome: {prediction!r}"
        )
    score = (prob - (1.0 if actual else 0.0)) ** 2
    return ResolutionResult(
        outcome_id=outcome.outcome_id,
        kind=OutcomeKind.BINARY,
        predicted=prob,
        actual=actual,
        score=score,
        resolved=True,
        resolution_source=outcome.resolution_source,
    )


def _resolve_interval(outcome: Outcome, prediction: Any) -> ResolutionResult:
    if isinstance(outcome.value, (int, float)):
        actual_value = float(outcome.value)
    else:
        raise ResolutionError(
            f"Interval outcome value must be numeric, got {type(outcome.value)}"
        )

    if isinstance(prediction, (int, float)):
        predicted_value = float(prediction)
        lower: Optional[float] = None
        upper: Optional[float] = None
    elif isinstance(prediction, dict):
        predicted_value = float(prediction.get("point", prediction.get("value", 0)))
        lower = prediction.get("lower")
        upper = prediction.get("upper")
        if lower is not None:
            lower = float(lower)
        if upper is not None:
            upper = float(upper)
    else:
        raise ResolutionError(
            f"Cannot interpret prediction for interval outcome: {prediction!r}"
        )

    score = (predicted_value - actual_value) ** 2
    hit = True
    if lower is not None and upper is not None:
        hit = lower <= actual_value <= upper

    return ResolutionResult(
        outcome_id=outcome.outcome_id,
        kind=OutcomeKind.INTERVAL,
        predicted=prediction,
        actual=actual_value,
        score=score,
        resolved=True,
        resolution_source=outcome.resolution_source,
        detail=f"interval_hit={hit}",
    )


def _resolve_preference(outcome: Outcome, prediction: Any) -> ResolutionResult:
    if not isinstance(outcome.value, str):
        raise ResolutionError(
            f"Preference outcome value must be a string (chosen option), got {type(outcome.value)}"
        )
    actual_choice = outcome.value

    if isinstance(prediction, str):
        predicted_choice = prediction
        score = 0.0 if predicted_choice == actual_choice else 1.0
    elif isinstance(prediction, dict):
        predicted_choice = prediction.get("choice", "")
        probs = prediction.get("probabilities", {})
        if probs and actual_choice in probs:
            p = float(probs[actual_choice])
            score = (1.0 - p) ** 2
        else:
            score = 0.0 if predicted_choice == actual_choice else 1.0
    else:
        raise ResolutionError(
            f"Cannot interpret prediction for preference outcome: {prediction!r}"
        )

    return ResolutionResult(
        outcome_id=outcome.outcome_id,
        kind=OutcomeKind.PREFERENCE,
        predicted=prediction,
        actual=actual_choice,
        score=score,
        resolved=True,
        resolution_source=outcome.resolution_source,
    )


_RESOLVERS = {
    OutcomeKind.BINARY: _resolve_binary,
    OutcomeKind.INTERVAL: _resolve_interval,
    OutcomeKind.PREFERENCE: _resolve_preference,
}


def resolve(outcome: Outcome, prediction: Any) -> ResolutionResult:
    """Resolve an outcome against a prediction.

    Every outcome MUST carry ``resolution_source``; this function does
    NOT self-grade — it merely computes the score from the externally-
    provided resolution.
    """
    if not outcome.resolution_source:
        raise ResolutionError(
            f"Outcome {outcome.outcome_id} has no resolution_source; cannot self-grade"
        )
    resolver = _RESOLVERS.get(outcome.kind)
    if resolver is None:
        raise ResolutionError(f"No resolver for outcome kind {outcome.kind}")
    return resolver(outcome, prediction)

"""Counterfactual runner: grades each method's predictive accuracy on held-out temporal slices."""

from __future__ import annotations

import logging
from datetime import datetime, timedelta, timezone
from typing import Any, Callable, Optional
from unittest.mock import patch
from uuid import uuid4

from noosphere.models import (
    CalibrationMetrics,
    CounterfactualEvalRun,
    MethodRef,
    Outcome,
    OutcomeKind,
    TemporalCut,
)
from noosphere.evaluation.outcomes import ResolutionResult, resolve
from noosphere.evaluation.metrics import compute_metrics_for_kind
from noosphere.evaluation.slicer import CorpusSlicer

logger = logging.getLogger(__name__)


class CounterfactualRunner:
    """Run methods against held-out temporal slices and grade predictions."""

    def __init__(
        self,
        store: Any,
        method_fn: Callable,
        method_ref: MethodRef,
        *,
        prediction_extractor: Optional[Callable] = None,
    ) -> None:
        self._store = store
        self._method_fn = method_fn
        self._method_ref = method_ref
        self._prediction_extractor = prediction_extractor or _default_extractor

    def run(
        self,
        window_start: datetime,
        window_end: datetime,
        cadence: timedelta,
        *,
        cuts: Optional[list[TemporalCut]] = None,
    ) -> CounterfactualEvalRun:
        run_id = f"cf-{uuid4().hex[:16]}"

        if cuts is None:
            cuts = self._generate_cuts(window_start, window_end, cadence)

        all_results: list[ResolutionResult] = []
        prediction_refs: list[str] = []
        total_by_kind: dict[OutcomeKind, int] = {}

        for cut in cuts:
            slicer = CorpusSlicer(self._store, cut)
            for outcome in cut.outcomes:
                total_by_kind[outcome.kind] = total_by_kind.get(outcome.kind, 0) + 1
                try:
                    with _block_network():
                        prediction = self._method_fn(slicer)
                except Exception:
                    logger.warning(
                        "Method %s failed on cut %s", self._method_ref.name, cut.cut_id,
                        exc_info=True,
                    )
                    continue

                extracted = self._prediction_extractor(prediction, outcome)
                if extracted is None:
                    continue

                try:
                    result = resolve(outcome, extracted)
                    all_results.append(result)
                    prediction_refs.append(
                        f"{cut.cut_id}:{outcome.outcome_id}"
                    )
                except Exception:
                    logger.warning(
                        "Resolution failed for outcome %s", outcome.outcome_id,
                        exc_info=True,
                    )

        metrics = self._aggregate_metrics(all_results, total_by_kind)

        return CounterfactualEvalRun(
            run_id=run_id,
            method_ref=self._method_ref,
            cut_id=cuts[0].cut_id if cuts else "",
            metrics=metrics,
            prediction_refs=prediction_refs,
            created_at=datetime.now(timezone.utc),
        )

    def _generate_cuts(
        self,
        window_start: datetime,
        window_end: datetime,
        cadence: timedelta,
    ) -> list[TemporalCut]:
        from noosphere.models import CorpusSelector

        cuts: list[TemporalCut] = []
        t = window_start
        while t <= window_end:
            outcomes = self._store.list_outcomes_for_cut(f"auto-{t.isoformat()}")
            cut = TemporalCut(
                cut_id=f"auto-{t.isoformat()}",
                as_of=t,
                corpus_slice=CorpusSelector(as_of=t),
                embargoed=CorpusSelector(as_of=t),
                embedding_version_pin="default",
                outcomes=outcomes if outcomes else [],
            )
            cuts.append(cut)
            t += cadence
        return cuts

    def _aggregate_metrics(
        self,
        results: list[ResolutionResult],
        total_by_kind: dict[OutcomeKind, int],
    ) -> CalibrationMetrics:
        if not results:
            return CalibrationMetrics(
                brier=0.0, log_loss=0.0, ece=0.0,
                reliability_bins=[], resolution=0.0, coverage=0.0,
            )
        present_kinds = {r.kind for r in results}
        if len(present_kinds) == 1:
            kind = next(iter(present_kinds))
            return compute_metrics_for_kind(
                results, kind, total_by_kind.get(kind, len(results))
            )
        first_kind = next(iter(sorted(present_kinds, key=lambda k: k.value)))
        return compute_metrics_for_kind(
            results, first_kind, total_by_kind.get(first_kind, len(results))
        )


def _default_extractor(prediction: Any, outcome: Outcome) -> Any:
    if isinstance(prediction, dict):
        return prediction.get("prediction", prediction.get("value", prediction))
    return prediction


class _block_network:
    """Context manager that patches socket to prevent network access."""

    def __enter__(self):
        import socket
        self._orig_connect = socket.socket.connect

        def _blocked(*args, **kwargs):
            raise RuntimeError("Network access blocked during counterfactual run")

        self._patch = patch.object(socket.socket, "connect", _blocked)
        self._patch.start()
        return self

    def __exit__(self, *exc):
        self._patch.stop()

